package de.drremote.dsp408controller.util;
public final class Hex { private Hex() { } public static byte[] parseFlexible(String text) { String cleaned = text .replace("0x", "") .replace("0X", "") .replaceAll("[^0-9A-Fa-f]", ""); if (cleaned.isEmpty()) { return new byte[0]; } if ((cleaned.length() & 1) != 0) { throw new IllegalArgumentException("Hex length is odd: " + cleaned); } byte[] bytes = new byte[cleaned.length() / 2]; for (int i = 0; i < cleaned.length(); i += 2) { bytes[i / 2] = (byte) Integer.parseInt(cleaned.substring(i, i + 2), 16); } return bytes; } public static String format(byte[] bytes) { StringBuilder sb = new StringBuilder(); for (int i = 0; i < bytes.length; i++) { if (i > 0) { sb.append(' '); } sb.append(byteToHex(bytes[i] & 0xFF)); } return sb.toString(); } public static String formatCompact(byte[] bytes) { StringBuilder sb = new StringBuilder(bytes.length * 2); for (byte b : bytes) { sb.append(byteToHex(b & 0xFF)); } return sb.toString(); } public static String byteToHex(int value) { return String.format("%02X", value & 0xFF); } public static byte parseByte(String text) { String cleaned = text.trim() .replace("0x", "") .replace("0X", ""); if (cleaned.length() != 2) { throw new IllegalArgumentException("Byte must be exactly 2 hex characters: " + text); } return (byte) Integer.parseInt(cleaned, 16); } public static int toInt16LE(byte low, byte high) { int value = (low & 0xFF) | ((high & 0xFF) << 8); if (value >= 0x8000) { value -= 0x10000; } return value; } public static byte[] fromUInt16LE(int value) { if (value < 0 || value > 0xFFFF) { throw new IllegalArgumentException("UInt16 out of range: " + value); } return new byte[]{(byte) (value & 0xFF), (byte) ((value >>> 8) & 0xFF)}; } public static String ascii(byte[] data) { StringBuilder sb = new StringBuilder(); for (byte b : data) { int v = b & 0xFF; if (v >= 32 && v <= 126) { sb.append((char) v); } else { sb.append('.'); } } return sb.toString(); } }